template IsInRange(n_bits) {
    signal input n;
    signal input low;
    signal input high;
    signal output out;

    component gte = GreaterEqThan(n_bits);
    gte.in[0] <== n;
    gte.in[1] <== low;

    component lte = LessEqThan(n_bits);
    lte.in[0] <== n;
    lte.in[1] <== high;

    out <== gte.out * lte.out;
}

component main = IsInRange(64);

