template IsPowerOfTwo(n_bits) {
    signal input n;
    signal output out;

    component gt0 = GreaterThan(n_bits);
    gt0.in[0] <== n;
    gt0.in[1] <== 0;

    component nBits = Num2Bits(n_bits);
    nBits.in <== n;

    signal n_minus_1 <== n - gt0.out;
    component nMinus1Bits = Num2Bits(n_bits);
    nMinus1Bits.in <== n_minus_1;

    signal bit_ands[n_bits];
    var sum_and = 0;
    for (var i = 0; i < n_bits; i++) {
        bit_ands[i] <== nBits.out[i] * nMinus1Bits.out[i];
        sum_and += bit_ands[i];
    }

    component is_zero = IsZero();
    is_zero.in <== sum_and;

    out <== gt0.out * is_zero.out;
}

component main = IsPowerOfTwo(64);

