template MedianOfThree() {
    signal input a;
    signal input b;
    signal input c;
    signal output out;

    component gteAB = GreaterEqThan(64);
    gteAB.in[0] <== a; gteAB.in[1] <== b;
    component gteAC = GreaterEqThan(64);
    gteAC.in[0] <== a; gteAC.in[1] <== c;
    component lteAB = LessEqThan(64);
    lteAB.in[0] <== a; lteAB.in[1] <== b;
    component lteAC = LessEqThan(64);
    lteAC.in[0] <== a; lteAC.in[1] <== c;

    signal condA1 <== gteAB.out * lteAC.out;
    signal condA2 <== lteAB.out * gteAC.out;
    signal isA <== condA1 + condA2 - (condA1 * condA2);

    component gteBA = GreaterEqThan(64);
    gteBA.in[0] <== b; gteBA.in[1] <== a;
    component gteBC = GreaterEqThan(64);
    gteBC.in[0] <== b; gteBC.in[1] <== c;
    component lteBA = LessEqThan(64);
    lteBA.in[0] <== b; lteBA.in[1] <== a;
    component lteBC = LessEqThan(64);
    lteBC.in[0] <== b; lteBC.in[1] <== c;

    signal condB1 <== gteBA.out * lteBC.out;
    signal condB2 <== lteBA.out * gteBC.out;
    signal isB_raw <== condB1 + condB2 - (condB1 * condB2);

    signal isB <== isB_raw * (1 - isA);
    signal isC <== (1 - isA) * (1 - isB);

    signal termA <== isA * a;
    signal termB <== isB * b;
    signal termC <== isC * c;

    out <== termA + termB + termC;
}

component main = MedianOfThree();

