template ModuloCheck(n_bits) {
    signal input a;
    signal input b;
    signal output is_zero;

    signal q <-- a \ b;
    signal r <-- a % b;

    a === q * b + r;

    component lte = LessThan(n_bits);
    lte.in[0] <== r;
    lte.in[1] <== b;
    lte.out === 1;

    component iz = IsZero();
    iz.in <== r;
    is_zero <== iz.out;
}

template IsLeapYear() {
    signal input year;
    signal output out;

    component mod4 = ModuloCheck(16);
    mod4.a <== year;
    mod4.b <== 4;

    component mod100 = ModuloCheck(16);
    mod100.a <== year;
    mod100.b <== 100;

    component mod400 = ModuloCheck(16);
    mod400.a <== year;
    mod400.b <== 400;

    signal is_div_4 <== mod4.is_zero;
    signal is_not_div_100 <== 1 - mod100.is_zero;
    signal is_div_400 <== mod400.is_zero;

    signal cond1 <== is_div_4 * is_not_div_100;

    out <== cond1 + is_div_400 - cond1 * is_div_400;
}

component main = IsLeapYear();

