template SumOfDigits3() {
    signal input n;
    signal output out;

    signal digit1;
    signal digit1_rem;
    signal digit2;
    signal digit3;

    digit1 <-- n \ 100;
    digit1_rem <-- n % 100;

    n === digit1 * 100 + digit1_rem;

    component check1 = LessThan(8);
    check1.in[0] <== digit1;
    check1.in[1] <== 10;
    check1.out === 1;

    digit2 <-- digit1_rem \ 10;
    digit3 <-- digit1_rem % 10;

    digit1_rem === digit2 * 10 + digit3;

    component check2 = LessThan(8);
    check2.in[0] <== digit2;
    check2.in[1] <== 10;
    check2.out === 1;

    component check3 = LessThan(8);
    check3.in[0] <== digit3;
    check3.in[1] <== 10;
    check3.out === 1;

    out <== digit1 + digit2 + digit3;
}

component main = SumOfDigits3();

