template BoundedDiff() {
    signal input a;
    signal input b;
    signal input bound;
    signal output out;
    var offset = 2**(64 - 1);
    signal d <== a - b;
    component lt = LessThan(64 + 1);
    lt.in[0] <== d + bound + offset;
    lt.in[1] <== offset;
    component gt = GreaterThan(64 + 1);
    gt.in[0] <== d + offset;
    gt.in[1] <== bound + offset;

    signal is_under <== lt.out;
    signal is_over <== gt.out;
    signal is_in_range <== (1 - is_under) * (1 - is_over);

    signal term1 <== is_under * (0 - bound);
    signal term2 <== is_over * bound;
    signal term3 <== is_in_range * d;

    out <== term1 + term2 + term3;
}

component main = BoundedDiff();

