template ScaledAttentionScore() {
    signal input q1;
    signal input q2;
    signal input k1;
    signal input k2;
    signal input s;
    signal output out;

    signal p1 <== q1 * k1;
    signal p2 <== q2 * k2;
    signal dot <== p1 + p2;

    component is_s_zero = IsZero();
    is_s_zero.in <== s;
    signal s_not_zero <== 1 - is_s_zero.out;

    component sign = Num2Bits(254);
    sign.in <== dot;
    signal is_neg <== sign.out[253];

    signal term_abs1 <== is_neg * (-dot);
    signal term_abs2 <== (1 - is_neg) * dot;
    signal abs_dot <== term_abs1 + term_abs2;

    signal abs_quotient;
    abs_quotient <-- (s != 0) ? abs_dot / s : 0;

    signal q_s <== abs_quotient * s;

    signal abs_remainder;
    abs_remainder <-- (s != 0) ? abs_dot % s : 0;

    signal check_sum <== q_s + abs_remainder;
    s_not_zero * (abs_dot - check_sum) === 0;

    signal term_q1 <== is_neg * (-abs_quotient);
    signal term_q2 <== (1 - is_neg) * abs_quotient;
    signal quotient <== term_q1 + term_q2;

    signal term_div <== s_not_zero * quotient;
    signal term_dot <== is_s_zero.out * dot;

    out <== term_div + term_dot;
}

component main = ScaledAttentionScore();

