template BinaryClassifyMargin() {
    signal input x;
    signal input w;
    signal input b;
    signal input t;
    signal input m;
    signal output out;

    signal score <== x * w + b;

    var offset = 2**63;

    component geHigh = GreaterEqThan(64);
    geHigh.in[0] <== score + offset;
    geHigh.in[1] <== t + m + offset;

    component ltLow = LessThan(64);
    ltLow.in[0] <== score + offset;
    ltLow.in[1] <== t - m + offset;

    signal is_one <== geHigh.out;
    signal is_zero <== ltLow.out;
    signal is_two <== (1 - is_one) * (1 - is_zero);

    out <== is_one * 1 + is_two * 2;
}

component main = BinaryClassifyMargin();

