template StochasticClip() {
    signal input v;
    signal input min_v;
    signal input max_v;
    signal input r;
    signal output out;

    var offset = 2**63;

    component gtR = GreaterThan(64);
    gtR.in[0] <== r;
    gtR.in[1] <== 90;

    component ltMin = LessThan(64);
    ltMin.in[0] <== v + offset;
    ltMin.in[1] <== min_v + offset;

    component gtMax = GreaterThan(64);
    gtMax.in[0] <== v + offset;
    gtMax.in[1] <== max_v + offset;

    signal is_r_high <== gtR.out;
    signal not_r_high <== 1 - is_r_high;

    signal is_v_low <== not_r_high * ltMin.out;

    signal not_v_low <== 1 - ltMin.out;
    signal v_high_candidate <== not_r_high * not_v_low;
    signal is_v_high <== v_high_candidate * gtMax.out;

    signal not_v_high <== 1 - gtMax.out;
    signal is_v_normal <== v_high_candidate * not_v_high;

    signal term_v_cond <== is_r_high + is_v_normal;
    signal term_v <== term_v_cond * v;
    signal term_min <== is_v_low * min_v;
    signal term_max <== is_v_high * max_v;

    out <== term_v + term_min + term_max;
}

component main = StochasticClip();

