template MomentumAccel() {
    signal input v;
    signal input g;
    signal input m;
    signal input s;
    signal output out;

    var offset = 2**63;

    signal term1 <== v * m;
    signal m_diff <== 100 - m;
    signal term2 <== g * m_diff;
    signal dividend <== term1 + term2;

    signal nv;
    signal remainder;

    nv <-- dividend / 100;
    remainder <-- dividend % 100;

    dividend === nv * 100 + remainder;

    component ltRem = LessThan(64);
    ltRem.in[0] <== remainder;
    ltRem.in[1] <== 100;
    ltRem.out === 1;

    component gt = GreaterThan(64);
    gt.in[0] <== nv + offset;
    gt.in[1] <== v + offset;

    signal is_gt <== gt.out;
    signal is_le <== 1 - is_gt;

    signal res_pos <== nv + s;
    signal res_neg <== nv - s;

    signal term_pos <== is_gt * res_pos;
    signal term_neg <== is_le * res_neg;

    out <== term_pos + term_neg;
}

component main = MomentumAccel();

