template DropoutRescale() {
    signal input x;
    signal input r;
    signal input t;
    signal input sn;
    signal input sd;
    signal output out;

    var offset = 2**63;

    component lt = LessThan(64);
    lt.in[0] <== r + offset;
    lt.in[1] <== t + offset;
    signal is_dropped <== lt.out;

    component iz = IsZero();
    iz.in <== sd;
    signal sd_is_zero <== iz.out;
    signal sd_not_zero <== 1 - sd_is_zero;

    signal active <== 1 - is_dropped;

    signal rescale_cond <== active * sd_not_zero;

    signal numerator <== x * sn;
    signal quotient;
    signal remainder;

    quotient <-- (sd != 0) ? numerator / sd : 0;
    remainder <-- (sd != 0) ? numerator % sd : 0;

    signal qs <== quotient * sd;
    rescale_cond * (numerator - (qs + remainder)) === 0;

    component ltRem = LessThan(64);
    ltRem.in[0] <== remainder;
    ltRem.in[1] <== sd + sd_is_zero;
    rescale_cond * (1 - ltRem.out) === 0;

    signal res_scaled <== rescale_cond * quotient;

    signal identity_cond <== active * sd_is_zero;
    signal res_identity <== identity_cond * x;

    out <== res_scaled + res_identity;
}

component main = DropoutRescale();

