            is_moved[i-1][j] <== gt[i-1][j].out;
            cnt[i-1][j+1] <== cnt[i-1][j] + is_moved[i-1][j];
        }

        pos[i-1] <== i - cnt[i-1][5];

        for (var j = 0; j < 5; j++) {
            is_key_pos[i-1][j] = IsEqual();
            is_key_pos[i-1][j].in[0] <== j;
            is_key_pos[i-1][j].in[1] <== pos[i-1];

            lt_pos[i-1][j] = LessThan(252);
            lt_pos[i-1][j].in[0] <== j;
            lt_pos[i-1][j].in[1] <== pos[i-1];

            gt_pos[i-1][j] = GreaterThan(252);
            gt_pos[i-1][j].in[0] <== j;
            gt_pos[i-1][j].in[1] <== pos[i-1];

            le_i[i-1][j] = LessThan(252);
