template LinearRegressionLeastSquares() {
    signal input x0, x1, x2, x3, y0, y1, y2, y3;
    signal output out;

    signal sx <== x0 + x1 + x2 + x3;
    signal sy <== y0 + y1 + y2 + y3;

    signal x0y0 <== x0 * y0;
    signal x1y1 <== x1 * y1;
    signal x2y2 <== x2 * y2;
    signal x3y3 <== x3 * y3;
    signal sxy <== x0y0 + x1y1 + x2y2 + x3y3;

    signal x0x0 <== x0 * x0;
    signal x1x1 <== x1 * x1;
    signal x2x2 <== x2 * x2;
    signal x3x3 <== x3 * x3;
    signal sxx <== x0x0 + x1x1 + x2x2 + x3x3;

    signal sxsy <== sx * sy;
    signal sxsx <== sx * sx;

    signal num <== 4 * sxy - sxsy;
    signal den <== 4 * sxx - sxsx;

    component den_is_zero = IsZero();
    den_is_zero.in <== den;

    signal num1000 <== num * 1000;

    component n2b_num = Num2Bits(254);
    n2b_num.in <== num1000;
    signal is_num_neg <== n2b_num.out[253]; 

    signal neg_num1000 <== 0 - num1000;
    signal part1_num <== is_num_neg * neg_num1000;
    signal is_num_pos <== 1 - is_num_neg;
    signal part2_num <== is_num_pos * num1000;
    signal abs_num1000 <== part1_num + part2_num;

    signal abs_slope;
    abs_slope <-- (den == 0) ? 0 : abs_num1000 \ den;
    signal rem_slope <-- (den == 0) ? 0 : abs_num1000 % den;

    signal abs_slope_den <== abs_slope * den;
    signal sl_check <== abs_num1000 - (abs_slope_den + rem_slope);
    (1 - den_is_zero.out) * sl_check === 0;

    signal neg_abs_slope <== 0 - abs_slope;
    signal s_p1 <== is_num_neg * neg_abs_slope;
    signal s_p2 <== is_num_pos * abs_slope;
    signal slope <== s_p1 + s_p2;

    signal slope_sx <== slope * sx;
    signal inter_num <== sy * 1000 - slope_sx;

    component n2b_inter = Num2Bits(254);
    n2b_inter.in <== inter_num;
    signal is_inter_neg <== n2b_inter.out[253];
    signal is_inter_pos <== 1 - is_inter_neg;

    signal neg_inter_num <== 0 - inter_num;
    signal i_p1_num <== is_inter_neg * neg_inter_num;
    signal i_p2_num <== is_inter_pos * inter_num;
    signal abs_inter_num <== i_p1_num + i_p2_num;

    signal abs_inter;
    abs_inter <-- abs_inter_num \ 4;
    signal rem_inter <-- abs_inter_num % 4;
    abs_inter_num === abs_inter * 4 + rem_inter;

    signal neg_abs_inter <== 0 - abs_inter;
    signal int_p1 <== is_inter_neg * neg_abs_inter;
    signal int_p2 <== is_inter_pos * abs_inter;
    signal inter <== int_p1 + int_p2;

    signal slope10000 <== slope * 10000;
    signal res <== slope10000 + inter;
    out <== (1 - den_is_zero.out) * res;
}

