    component lt_100 = LessThan(252);
    lt_100.in[0] <== post_b_rem_100;
    lt_100.in[1] <== 100;
    lt_100.out === 1;

    signal res <== post_a + post_b_div_100;
    out <== p_e_not_zero * res;
}

