template PearsonCorrelationFixed() {
    signal input x0, x1, x2, y0, y1, y2;
    signal output out;

    signal sum_x <== x0 + x1 + x2;
    signal sum_y <== y0 + y1 + y2;

    signal mx;
    signal rem_x;
    mx <-- sum_x \ 3;
    rem_x <-- sum_x % 3;
    sum_x === mx * 3 + rem_x;

    signal my;
    signal rem_y;
    my <-- sum_y \ 3;
    rem_y <-- sum_y % 3;
    sum_y === my * 3 + rem_y;

    signal dx[3];
    signal dy[3];
    signal dx_dy[3];
    signal dx_dx[3];
    signal dy_dy[3];

    for (var i = 0; i < 3; i++) {
        var xi;
        var yi;
        if (i == 0) {
            xi = x0;
            yi = y0;
        } else if (i == 1) {
            xi = x1;
            yi = y1;
        } else {
            xi = x2;
            yi = y2;
        }

        dx[i] <== xi - mx;
        dy[i] <== yi - my;

        dx_dy[i] <== dx[i] * dy[i];
        dx_dx[i] <== dx[i] * dx[i];
        dy_dy[i] <== dy[i] * dy[i];
    }

    signal num <== dx_dy[0] + dx_dy[1] + dx_dy[2];
    signal dxs <== dx_dx[0] + dx_dx[1] + dx_dx[2];
    signal dys <== dy_dy[0] + dy_dy[1] + dy_dy[2];

    component dxs_zero = IsZero();
    dxs_zero.in <== dxs;
    component dys_zero = IsZero();
    dys_zero.in <== dys;

    signal den_is_zero <== dxs_zero.out + dys_zero.out - dxs_zero.out * dys_zero.out;
    signal is_valid <== 1 - den_is_zero;

    signal num_sq <== num * num;
    signal dividend <== num_sq * 10000;
    signal divisor <== dxs * dys;

    signal res;
    signal rem_res;

    res <-- (divisor == 0) ? 0 : dividend \ divisor;
    rem_res <-- (divisor == 0) ? 0 : dividend % divisor;

    signal check_div <== res * divisor;
    is_valid * (dividend - (check_div + rem_res)) === 0;

    out <== is_valid * res;
}

