    signal m2;
    signal rem2;
    m2 <-- g2_s \ g2_n;
    rem2 <-- g2_s % g2_n;
    g2_s === m2 * g2_n + rem2;

    signal total_s <== g1_s + g2_s;
    signal total_n <== g1_n + g2_n;
    signal gm;
    signal rem_gm;
    gm <-- total_s \ total_n;
    rem_gm <-- total_s % total_n;
    total_s === gm * total_n + rem_gm;

    signal diff1 <== m1 - gm;
    signal diff2 <== m2 - gm;
