    signal ssw_gt_0 <== 1 - ssw_le_0;

    signal dividend <== ssb * 100;
    signal res_div;
    signal rem_div;

    signal safe_ssw <== ssw + ssw_le_0; 
    res_div <-- (ssw_le_0 == 1) ? 0 : dividend \ safe_ssw;
    rem_div <-- (ssw_le_0 == 1) ? 0 : dividend % safe_ssw;

    signal check_div <== res_div * safe_ssw;
    ssw_gt_0 * (dividend - (check_div + rem_div)) === 0;

    signal final_res <== res_div + gm;

    signal term1 <== ssw_le_0 * gm;
    signal term2 <== ssw_gt_0 * final_res;
