template AutoregressiveAr1Logic() {
    signal input y0, phi, noise, steps;
    signal output out;

    signal cy[4];
    signal step_count[4];
    signal prod[3];
    signal quotient[3];
    signal remainder[3];
    signal next_val[3];
    signal diff[3];
    signal change[3];

    component gt[3];
    component lt_rem[3];

    cy[0] <== y0;
    step_count[0] <== steps;

    for (var i = 0; i < 3; i++) {
        gt[i] = GreaterThan(32);
        gt[i].in[0] <== step_count[i];
        gt[i].in[1] <== 0;

        prod[i] <== phi * cy[i];

        quotient[i] <-- prod[i] \ 100;
        remainder[i] <-- prod[i] % 100;

        prod[i] === quotient[i] * 100 + remainder[i];

        lt_rem[i] = LessThan(8);
        lt_rem[i].in[0] <== remainder[i];
        lt_rem[i].in[1] <== 100;
        lt_rem[i].out === 1;

        next_val[i] <== quotient[i] + noise;

        diff[i] <== next_val[i] - cy[i];
        change[i] <== gt[i].out * diff[i];
        cy[i+1] <== change[i] + cy[i];

        step_count[i+1] <== step_count[i] - gt[i].out;
    }

    out <== cy[3];
}

