template SampleQuantileLinearLogic() {
    signal input a0, a1, a2, a3, a4, q_s;
    signal output out;

    var input_vals[5] = [a0, a1, a2, a3, a4];
    var sorted_vals[5];
    for (var i = 0; i < 5; i++) { sorted_vals[i] = input_vals[i]; }

    var t;
    for (var i = 0; i < 5; i++) {
        for (var j = 0; j < 4 - i; j++) {
            if (sorted_vals[j] > sorted_vals[j+1]) {
                t = sorted_vals[j];
                sorted_vals[j] = sorted_vals[j+1];
                sorted_vals[j+1] = t;
            }
        }
    }

    signal s[5];
    for (var i = 0; i < 5; i++) {
        s[i] <-- sorted_vals[i];
    }
    component lte[4];
    for (var i = 0; i < 4; i++) {
        lte[i] = LessEqThan(32);
        lte[i].in[0] <== s[i];
        lte[i].in[1] <== s[i+1];
        lte[i].out === 1;
    }
    s[0] + s[1] + s[2] + s[3] + s[4] === a0 + a1 + a2 + a3 + a4;

    signal idxs <== 4 * q_s;
    signal idx;
    signal rem;
    idx <-- idxs \ 100;
    rem <-- idxs % 100;
    idxs === idx * 100 + rem;

    component ge4 = GreaterEqThan(8);
    ge4.in[0] <== idx;
    ge4.in[1] <== 4;

    component eq[5];
    component eq_next[5];
    signal val_idx[5];
    signal val_idx_next[5];

    for (var i = 0; i < 5; i++) {
        eq[i] = IsEqual();
        eq[i].in[0] <== idx;
        eq[i].in[1] <== i;
        val_idx[i] <== eq[i].out * s[i];

        eq_next[i] = IsEqual();
        eq_next[i].in[0] <== idx + 1;
        eq_next[i].in[1] <== i;
        val_idx_next[i] <== eq_next[i].out * s[i];
    }

    signal arr_idx <== val_idx[0] + val_idx[1] + val_idx[2] + val_idx[3] + val_idx[4];
    signal arr_idx_next <== val_idx_next[0] + val_idx_next[1] + val_idx_next[2] + val_idx_next[3] + val_idx_next[4];

    signal diff <== arr_idx_next - arr_idx;
    signal term2 <== rem * diff;
    signal res <== arr_idx * 100 + term2;

    signal res_div;
    signal res_rem;
    res_div <-- res \ 100;
    res_rem <-- res % 100;
    res === res_div * 100 + res_rem;

    signal diff_final <== s[4] - res_div;
    signal choice <== ge4.out * diff_final;
    out <== choice + res_div;
}

component main = SampleQuantileLinearLogic();

