template RpgComplexDamagePipeline() {
    signal input ba, ap, fa, cr, cd, dv, rv, am;
    signal output out;

    signal ap_term <== 100 + ap;
    signal ba_ap <== ba * ap_term;
    signal ta_base;
    signal ta_rem;
    ta_base <-- ba_ap \ 100;
    ta_rem <-- ba_ap % 100;
    ba_ap === ta_base * 100 + ta_rem;
    signal ta <== ta_base + fa;

    signal dd <== dv + 800;
    signal dm;
    signal dm_rem;
    dm <-- 80000 \ dd;
    dm_rem <-- 80000 % dd;
    80000 === dm * dd + dm_rem;

    component n2b = Num2Bits(254);
    n2b.in <== rv;
    signal is_rv_neg <== n2b.out[253];

    signal neg_rv <== 0 - rv;
    signal term_abs_neg <== is_rv_neg * neg_rv;
    signal term_abs_pos <== (1 - is_rv_neg) * rv;
    signal abs_rv <== term_abs_neg + term_abs_pos;

    signal abs_rv_div2;
    signal abs_rv_rem2;
    abs_rv_div2 <-- abs_rv \ 2;
    abs_rv_rem2 <-- abs_rv % 2;
    abs_rv === abs_rv_div2 * 2 + abs_rv_rem2;

    signal neg_abs_div2 <== 0 - abs_rv_div2;
    signal term_rv2_neg <== is_rv_neg * neg_abs_div2;
    signal term_rv2_pos <== (1 - is_rv_neg) * abs_rv_div2;
    signal rv_div2 <== term_rv2_neg + term_rv2_pos;

    signal rm_neg <== 100 - rv_div2;
    signal rm_pos <== 100 - rv;
    signal rm <== is_rv_neg * (rm_neg - rm_pos) + rm_pos;

    component gt50 = GreaterThan(32);
    gt50.in[0] <== cr;
    gt50.in[1] <== 50;
    signal cm <== gt50.out * cd + 100;

    signal m1 <== ta * cm;
    signal m2 <== m1 * dm;
    signal m3 <== m2 * rm;
    signal final_dividend <== m3 * am;

    signal res;
    signal res_rem;
    res <-- final_dividend \ 1000000;
    res_rem <-- final_dividend % 1000000;

    signal check_final <== res * 1000000;
    final_dividend === check_final + res_rem;

    out <== res;
}

