    signal dx <== p1x - p2x;
    signal dy <== p1y - p2y;
    signal dx2 <== dx * dx;
    signal dy2 <== dy * dy;
    signal ds <== dx2 + dy2;

    component gt_ds = GreaterThan(252);
    gt_ds.in[0] <== ds;
    gt_ds.in[1] <== rs;

    signal tm <== m1 + m2;
    component iz_tm = IsZero();
    iz_tm.in <== tm;
    signal tm_not_zero <== 1 - iz_tm.out;

    signal m_diff <== m1 - m2;
    signal term1x <== v1x * m_diff;
    signal term2x <== 2 * m2 * v2x;
    signal dividend_x <== term1x + term2x;

    component n2b_x = Num2Bits(254);
    n2b_x.in <== dividend_x;
    signal is_x_neg <== n2b_x.out[253];

    signal neg_dividend_x <== 0 - dividend_x;
    signal part_abs_x_1 <== is_x_neg * neg_dividend_x;
    signal part_abs_x_2 <== (1 - is_x_neg) * dividend_x;
    signal abs_div_x <== part_abs_x_1 + part_abs_x_2;

    signal abs_nv1x;
    signal rem_x;
    abs_nv1x <-- tm_not_zero == 0 ? 0 : abs_div_x \ tm;
    rem_x <-- tm_not_zero == 0 ? 0 : abs_div_x % tm;

    signal check_x <== abs_nv1x * tm;
    abs_div_x === check_x + rem_x;

    signal neg_abs_nv1x <== 0 - abs_nv1x;
    signal part_nv1x_1 <== is_x_neg * neg_abs_nv1x;
    signal part_nv1x_2 <== (1 - is_x_neg) * abs_nv1x;
    signal nv1x <== part_nv1x_1 + part_nv1x_2;

    signal term1y <== v1y * m_diff;
    signal term2y <== 2 * m2 * v2y;
    signal dividend_y <== term1y + term2y;

    component n2b_y = Num2Bits(254);
    n2b_y.in <== dividend_y;
    signal is_y_neg <== n2b_y.out[253];

    signal neg_dividend_y <== 0 - dividend_y;
    signal part_abs_y_1 <== is_y_neg * neg_dividend_y;
    signal part_abs_y_2 <== (1 - is_y_neg) * dividend_y;
    signal abs_div_y <== part_abs_y_1 + part_abs_y_2;

    signal abs_nv1y;
    signal rem_y;
    abs_nv1y <-- tm_not_zero == 0 ? 0 : abs_div_y \ tm;
    rem_y <-- tm_not_zero == 0 ? 0 : abs_div_y % tm;

    signal check_y <== abs_nv1y * tm;
    abs_div_y === check_y + rem_y;

    signal neg_abs_nv1y <== 0 - abs_nv1y;
    signal part_nv1y_1 <== is_y_neg * neg_abs_nv1y;
    signal part_nv1y_2 <== (1 - is_y_neg) * abs_nv1y;
    signal nv1y <== part_nv1y_1 + part_nv1y_2;

    signal f1x <== nv1x * 90;
    component n2b_f1x = Num2Bits(254);
    n2b_f1x.in <== f1x;
    signal is_f1x_neg <== n2b_f1x.out[253];
    signal neg_f1x <== 0 - f1x;
    signal part_f1x_1 <== is_f1x_neg * neg_f1x;
    signal part_f1x_2 <== (1 - is_f1x_neg) * f1x;
    signal abs_f1x <== part_f1x_1 + part_f1x_2;

    signal abs_res_x;
    signal abs_rem_x;
    abs_res_x <-- abs_f1x \ 100;
    abs_rem_x <-- abs_f1x % 100;
    signal check_f1x <== abs_res_x * 100;
    abs_f1x === check_f1x + abs_rem_x;

    signal neg_abs_res_x <== 0 - abs_res_x;
    signal part_res_x_1 <== is_f1x_neg * neg_abs_res_x;
    signal part_res_x_2 <== (1 - is_f1x_neg) * abs_res_x;
    signal res_x <== part_res_x_1 + part_res_x_2;

    signal f1y <== nv1y * 90;
    component n2b_f1y = Num2Bits(254);
    n2b_f1y.in <== f1y;
    signal is_f1y_neg <== n2b_f1y.out[253];
    signal neg_f1y <== 0 - f1y;
    signal part_f1y_1 <== is_f1y_neg * neg_f1y;
    signal part_f1y_2 <== (1 - is_f1y_neg) * f1y;
    signal abs_f1y <== part_f1y_1 + part_f1y_2;

    signal abs_res_y;
    signal abs_rem_y;
    abs_res_y <-- abs_f1y \ 100;
    abs_rem_y <-- abs_f1y % 100;
    signal check_f1y <== abs_res_y * 100;
    abs_f1y === check_f1y + abs_rem_y;

    signal neg_abs_res_y <== 0 - abs_res_y;
    signal part_res_y_1 <== is_f1y_neg * neg_abs_res_y;
    signal part_res_y_2 <== (1 - is_f1y_neg) * abs_res_y;
    signal res_y <== part_res_y_1 + part_res_y_2;

    signal collision_out <== res_x + res_y;
    signal after_tm_check <== tm_not_zero * collision_out;
    signal default_out <== v1x + v1y;

    signal diff_out <== default_out - after_tm_check;
    signal final_choice <== gt_ds.out * diff_out;
    out <== final_choice + after_tm_check;
}

