template ShuffleIntegrityLogic() {
    signal input c0, c1, c2, c3, c4;
    signal input s0, s1, s2, s3, s4;
    signal input sd; 
    signal output out;

    signal sc <== c0 + c1 + c2 + c3 + c4;
    signal ss <== s0 + s1 + s2 + s3 + s4;
    component eq_sum = IsEqual();
    eq_sum.in[0] <== sc;
    eq_sum.in[1] <== ss;

    signal c02 <== c0 * c0;
    signal c12 <== c1 * c1;
    signal c22 <== c2 * c2;
    signal c32 <== c3 * c3;
    signal c42 <== c4 * c4;
    signal qc <== c02 + c12 + c22 + c32 + c42;

    signal s02 <== s0 * s0;
    signal s12 <== s1 * s1;
    signal s22 <== s2 * s2;
    signal s32 <== s3 * s3;
    signal s42 <== s4 * s4;
    signal qs <== s02 + s12 + s22 + s32 + s42;

    component eq_qsum = IsEqual();
    eq_qsum.in[0] <== qc;
    eq_qsum.in[1] <== qs;

    signal valid <== eq_sum.out * eq_qsum.out;

    component eq_c[5];
    for (var i = 0; i < 5; i++) {
        eq_c[i] = IsEqual();
        eq_c[i].in[0] <== s0;
    }
    eq_c[0].in[1] <== c0;
    eq_c[1].in[1] <== c1;
    eq_c[2].in[1] <== c2;
    eq_c[3].in[1] <== c3;
    eq_c[4].in[1] <== c4;

    signal found_raw <== eq_c[0].out + eq_c[1].out + eq_c[2].out + eq_c[3].out + eq_c[4].out;
    component iz_found = IsZero();
    iz_found.in <== found_raw;
    signal found <== 1 - iz_found.out;
    signal iv <== found * 100;

    signal s[5];
    s[0] <== s0;
    s[1] <== s1;
    s[2] <== s2;
    s[3] <== s3;
    s[4] <== s4;

    component gt[10]; 
    signal gts[10];
    var k = 0;
    for (var i = 0; i < 5; i++) {
        for (var j = i + 1; j < 5; j++) {
            gt[k] = GreaterThan(32);
            gt[k].in[0] <== s[i];
            gt[k].in[1] <== s[j];
            gts[k] <== gt[k].out;
            k++;
        }
    }

    signal inv <== gts[0] + gts[1] + gts[2] + gts[3] + gts[4] + 
                  gts[5] + gts[6] + gts[7] + gts[8] + gts[9];

    signal total <== inv + iv;
    out <== valid * total;
}

