template ExtensiveFormSubgamePerfect() {
    signal input p1c1, p1c2, p2c11, p2c12, p2c21, p2c22;
    signal output out;

    component gt1 = GreaterThan(32);
    gt1.in[0] <== p2c11;
    gt1.in[1] <== p2c12;

    signal b1 <== gt1.out * (p2c11 - p2c12) + p2c12;

    component gt2 = GreaterThan(32);
    gt2.in[0] <== p2c21;
    gt2.in[1] <== p2c22;

    signal b2 <== gt2.out * (p2c21 - p2c22) + p2c22;

    signal sum_p1 <== p1c1 + p1c2;
    signal dummy;
    signal rem_dummy;
    dummy <-- sum_p1 \ 100000;
    rem_dummy <-- sum_p1 % 100000;
    sum_p1 === dummy * 100000 + rem_dummy;

    component gt_final = GreaterThan(32);
    gt_final.in[0] <== b1;
    gt_final.in[1] <== b2;

    signal path_base <== gt_final.out * (1 - 2) + 2; 
    out <== path_base + dummy;
}

component main = ExtensiveFormSubgamePerfect();

