include "node_modules/circomlib/circuits/bitify.circom";

template CournotCompetitionEquilibrium() {
    signal input a, c, n, qo;
    signal output out;
    signal diff_ac <== a - c;
    signal q_raw <== diff_ac - qo;


    component n2b = Num2Bits(254);
    n2b.in <== q_raw;
    signal is_neg <== n2b.out[253];
    signal is_pos <== 1 - is_neg;
    signal abs_q_raw <== is_pos * q_raw; 

    signal q_div2;
    signal q_rem;
    q_div2 <-- abs_q_raw \ 2;
    q_rem <-- abs_q_raw % 2;

    abs_q_raw === q_div2 * 2 + q_rem;

    signal dummy;
    signal rem_n;
    dummy <-- n \ 1000;
    rem_n <-- n % 1000;
    n === dummy * 1000 + rem_n;
    out <== q_div2 + dummy;
}

component main = CournotCompetitionEquilibrium();

