template SignalGameBayesLogic() {
    signal input prior, p_s1_t1, p_s1_t2;
    signal output out;
    signal num <== prior * p_s1_t1;
    signal type2_weight <== 100 - prior;
    signal type2_prob <== type2_weight * p_s1_t2;
    signal den <== num + type2_prob;
    component iz = IsZero();
    iz.in <== den;
    signal is_not_zero <== 1 - iz.out;
    signal scaled_num <== num * 100;

    signal res_raw;
    signal rem;
    res_raw <-- is_not_zero == 1 ? scaled_num \ den : 0;
    rem <-- is_not_zero == 1 ? scaled_num % den : 0;
    signal check_mul <== res_raw * den;
    is_not_zero * (scaled_num - (check_mul + rem)) === 0;
    out <== is_not_zero * res_raw;
}

component main = SignalGameBayesLogic();

