include "node_modules/circomlib/circuits/comparators.circom";

template ShapleyValueSimple3p() {
    signal input v1, v2, v3, v12, v13, v23, v123;
    signal output out;

    signal m1 <== v1;
    signal m12 <== v12 - v2;
    signal m13 <== v13 - v3;
    signal m123 <== v123 - v23;

    signal term1 <== 2 * m1;
    signal term2 <== 2 * m123;
    signal sum_m <== term1 + m12 + m13 + term2;

    signal res;
    signal rem;
    res <-- sum_m \ 6;
    rem <-- sum_m % 6;

    signal check_res <== res * 6;
    sum_m === check_res + rem;

    out <== res;
}

component main = ShapleyValueSimple3p();
